 75→    { hotkey: 'E', label: 'Hold Position', iconKey: 'holdPosition' as const, state: 'ready' as const },
 76→    { hotkey: 'R', label: 'Attack', iconKey: 'attack' as const, state: 'ready' as const },
 77→    { hotkey: 'A', label: 'Patrol', iconKey: 'patrol' as const, state: 'ready' as const },
 78→    { hotkey: 'S', label: 'Empty Slot', state: 'empty' as const },
 79→    { hotkey: 'D', label: 'Empty Slot', state: 'empty' as const },
 80→    { hotkey: 'F', label: 'Learn Skill', iconKey: 'skillz' as const, state: 'levelup' as const },
 81→    { hotkey: 'Z', label: 'Wind Walk', iconKey: 'windWalk' as const, state: 'active' as const },
 82→    { hotkey: 'X', label: 'Mirror Image', iconKey: 'mirrorImage' as const, state: 'ready' as const },
 83→    { hotkey: 'C', label: 'Critical Strike', iconKey: 'criticalStrike' as const, state: 'passive' as const },
 84→    { hotkey: 'V', label: 'Bladestorm', iconKey: 'bladestorm' as const, state: 'ready' as const },
 85→  ];
 86→
 87→  return (
 88→    <section className="section-card">
 89→      <h3>CommandCard</h3>
 90→      <p className="section-desc">
 91→        A spatial action grid with hotkey hints, cooldown states, and empty-slot affordances. Faster than a command palette — your users already know the layout.
 92→      </p>
 93→      <div className="command-card-preview">
 94→        <div className="command-card-grid" role="grid" aria-label="Command card preview">
 95→          {slots.map((slot) => (
 96→            <div key={slot.hotkey} className="command-card-cell" role="gridcell">
 97→              {slot.state === 'empty' ? (
 98→                <div
 99→                  className="cmd-btn cmd-btn-empty"
100→                  aria-hidden="true"
101→                >
102→                  {props.groupBorderUrl && <img src={props.groupBorderUrl} alt="" className="cmd-btn-frame" />}
103→                </div>
104→              ) : (
105→                (() => {
106→                  const iconUrl = slot.iconKey ? (props.iconUrls?.[slot.iconKey] || '') : '';
107→                  const showHighlight = slot.state === 'active';
108→
109→                  return (
110→                    <button
111→                      type="button"
112→                      className={`cmd-btn${slot.state === 'passive' ? ' cmd-btn--passive' : ''}${slot.state === 'levelup' ? ' cmd-btn--levelup' : ''}`}
113→                      aria-label={`${slot.label}${slot.hotkey ? ` (${slot.hotkey})` : ''}`}
114→                      aria-keyshortcuts={slot.hotkey || undefined}
115→                    >
116→                      {iconUrl ? (
117→                        <img src={iconUrl} alt="" className="cmd-btn-icon" />
118→                      ) : (
119→                        <div className="cmd-btn-fallback-icon" aria-hidden="true">*</div>
120→                      )}
121→                      {props.groupBorderUrl && <img src={props.groupBorderUrl} alt="" className="cmd-btn-frame" />}
122→                      {showHighlight && (
123→                        <div
124→                          className="cmd-btn-highlight cmd-btn-highlight--on"
125→                          style={props.highlightUrl ? { backgroundImage: `url("${props.highlightUrl}")` } : undefined}
126→                        />
127→                      )}
128→                      {slot.hotkey && <span className="cmd-btn-hotkey" aria-hidden="true">{slot.hotkey}</span>}
129→                    </button>
130→                  );
131→                })()
132→              )}
133→            </div>
134→          ))}
135→        </div>
136→      </div>
137→    </section>
138→  );
139→}
