 19→export async function loadBlpDataUrl(path: string): Promise<string> {
 20→  const cached = iconDataUrlCache.get(path);
 21→  if (cached) return cached;
 22→
 23→  const promise = (async () => {
 24→    const res = await fetch(path);
 25→    if (!res.ok) throw new Error(`Failed to fetch icon ${path}`);
 26→    const ab = await res.arrayBuffer();
 27→    const blp = decodeBLP(ab);
 28→    const img = getBLPImageData(blp, 0);
 29→    const pixelData = new Uint8ClampedArray(img.data);
 30→    if (shouldForceOpaqueOnZeroAlpha(path)) {
 31→      let allAlphaZero = true;
 32→      for (let i = 3; i < pixelData.length; i += 4) {
 33→        if (pixelData[i] !== 0) {
 34→          allAlphaZero = false;
 35→          break;
 36→        }
 37→      }
 38→      if (allAlphaZero) {
 39→        for (let i = 3; i < pixelData.length; i += 4) {
 40→          pixelData[i] = 255;
 41→        }
 42→      }
 43→    }
 44→    if (shouldApplyBlackColorKey(path)) {
 45→      for (let i = 0; i < pixelData.length; i += 4) {
 46→        const r = pixelData[i];
 47→        const g = pixelData[i + 1];
 48→        const b = pixelData[i + 2];
 49→        const a = pixelData[i + 3];
 50→        if (a > 224 && r <= 10 && g <= 10 && b <= 10) {
 51→          pixelData[i + 3] = 0;
 52→        }
 53→      }
 54→    }
 55→    const canvas = document.createElement("canvas");
 56→    canvas.width = img.width;
 57→    canvas.height = img.height;
 58→    const ctx = canvas.getContext("2d");
 59→    if (!ctx) throw new Error(`Failed to decode icon ${path}`);
 60→    ctx.putImageData(new ImageData(pixelData, img.width, img.height), 0, 0);
 61→    return canvas.toDataURL("image/png");
 62→  })();
 63→
 64→  iconDataUrlCache.set(path, promise);
 65→  return promise;
 66→}
