 68→export async function loadDataUrlImage(url: string): Promise<HTMLImageElement> {
 69→  const cached = decodedImageCache.get(url);
 70→  if (cached) return cached;
 71→  const promise = new Promise<HTMLImageElement>((resolve, reject) => {
 72→    const img = new Image();
 73→    img.onload = () => resolve(img);
 74→    img.onerror = reject;
 75→    img.src = url;
 76→  });
 77→  decodedImageCache.set(url, promise);
 78→  return promise;
 79→}
